content:
/* Task progress */
  .task-progress{align-self:flex-start;background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:12px 16px;font-size:13px;max-width:75%;width:320px}
  .task-progress .tp-header{display:flex;align-items:center;gap:8px;margin-bottom:8px;color:var(--accent);font-weight:600;font-size:13px}
  .task-progress .tp-header .tp-spinner{width:14px;height:14px;border:2px solid var(--border);border-top-color:var(--accent);border-radius:50%;animation:spin .8s linear infinite}
  @keyframes spin{to{transform:rotate(360deg)}}
  .task-progress .tp-bar{height:4px;background:var(--border);border-radius:2px;overflow:hidden;margin-bottom:6px}
  .task-progress .tp-bar .tp-fill{height:100%;background:var(--accent);transition:width .4s ease;border-radius:2px}
  .task-progress .tp-step{font-size:12px;color:var(--dim);padding:2px 0;display:flex;gap:6px;align-items:baseline}
  .task-progress .tp-step.done{color:var(--ma)}
  .task-progress .tp-step.active{color:var(--accent)}
  .task-progress .tp-step .tp-icon{min-width:14px;text-align:center}
